import React, { useRef, useEffect } from 'react';
import * as THREE from 'three';

function createRoundedPlaneGeo(size, radius) {
  const s = size / 2, r = radius;
  const shape = new THREE.Shape();
  shape.moveTo(-s+r,-s); shape.lineTo(s-r,-s);
  shape.quadraticCurveTo(s,-s,s,-s+r); shape.lineTo(s,s-r);
  shape.quadraticCurveTo(s,s,s-r,s); shape.lineTo(-s+r,s);
  shape.quadraticCurveTo(-s,s,-s,s-r); shape.lineTo(-s,-s+r);
  shape.quadraticCurveTo(-s,-s,-s+r,-s);
  return new THREE.ShapeGeometry(shape);
}

export default function RubikCube({ onRoll, maxRolls, onEnd, active }) {
  const mountRef = useRef(null);
  const activeRef = useRef(active);
  activeRef.current = active;

  useEffect(() => {
    const container = mountRef.current;
    if (!container) return;

    // Thud sound using Web Audio API
    let audioCtx = null;
    const playThud = () => {
      if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      if (audioCtx.state === 'suspended') audioCtx.resume();

      const osc = audioCtx.createOscillator();
      const gain = audioCtx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(80, audioCtx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(30, audioCtx.currentTime + 0.15);
      gain.gain.setValueAtTime(0.3, audioCtx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 0.2);
      osc.connect(gain);
      gain.connect(audioCtx.destination);
      osc.start(audioCtx.currentTime);
      osc.stop(audioCtx.currentTime + 0.2);

      // Add a noise burst for impact texture
      const bufferSize = audioCtx.sampleRate * 0.05;
      const buffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1) * Math.pow(1 - i / bufferSize, 3);
      }
      const noise = audioCtx.createBufferSource();
      noise.buffer = buffer;
      const noiseGain = audioCtx.createGain();
      noiseGain.gain.setValueAtTime(0.15, audioCtx.currentTime);
      noiseGain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 0.08);
      noise.connect(noiseGain);
      noiseGain.connect(audioCtx.destination);
      noise.start(audioCtx.currentTime);
    };
    const w = container.clientWidth || 400;
    const h = container.clientHeight || 400;

    const scene = new THREE.Scene();
    const aspect = w / h;
    const isMobile = window.innerWidth <= 768;
    const viewSize = isMobile ? 4 : 5;
    const camera = new THREE.OrthographicCamera(
      -viewSize * aspect, viewSize * aspect,
      viewSize, -viewSize,
      0.1, 100
    );

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(window.devicePixelRatio);
    renderer.setClearColor(0x000000, 0);
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    container.appendChild(renderer.domElement);

    scene.add(new THREE.AmbientLight(0xffffff, 1.2));
    const dir = new THREE.DirectionalLight(0xffffff, 0.3);
    dir.position.set(8, 8, 3);
    dir.castShadow = true;
    dir.shadow.mapSize.width = 1024;
    dir.shadow.mapSize.height = 1024;
    dir.shadow.camera.near = 0.1;
    dir.shadow.camera.far = 30;
    dir.shadow.camera.left = -10;
    dir.shadow.camera.right = 10;
    dir.shadow.camera.top = 10;
    dir.shadow.camera.bottom = -10;
    dir.shadow.bias = -0.002;
    scene.add(dir);

    const isLight = document.documentElement.getAttribute('data-theme') === 'light';

    // Floor plane to receive shadows
    const floorGeo = new THREE.PlaneGeometry(100, 20);
    const floorMat = new THREE.ShadowMaterial({ opacity: isLight ? 0.06 : 0.35 });
    const floor = new THREE.Mesh(floorGeo, floorMat);
    floor.rotation.x = -Math.PI / 2;
    floor.position.y = -0.01;
    floor.receiveShadow = true;
    scene.add(floor);

    const totalRolls = maxRolls || 6;
    const mobileFactor = isMobile ? 1.2 : 0.4;
    const S = (viewSize * aspect * 2 * mobileFactor) / totalRolls;
    const gap = S / 3;
    const planeSize = gap * 0.94;
    const radius = gap * 0.12;
    const offset = gap / 2;
    const H = S / 2;

    // Build the 3x3 cube centered at origin
    const cubeObj = new THREE.Group();
    const whiteMat = isLight
      ? new THREE.MeshBasicMaterial({ color: '#ffffff', side: THREE.DoubleSide })
      : new THREE.MeshStandardMaterial({ color: '#2F2F2F', side: THREE.DoubleSide, roughness: 0.8, metalness: 0.1 });
    const purpleMat = isLight
      ? new THREE.MeshBasicMaterial({ color: '#F3EAF9', side: THREE.DoubleSide })
      : new THREE.MeshStandardMaterial({ color: '#675B56', side: THREE.DoubleSide, roughness: 0.8, metalness: 0.1 });
    const edgeMat = new THREE.LineBasicMaterial({ color: isLight ? 0x000000 : 0xE4E4E4, opacity: 0.5, transparent: true });
    const planeGeo = createRoundedPlaneGeo(planeSize, radius);
    const flatGeo = new THREE.PlaneGeometry(planeSize, planeSize);

    // Collect material refs for theme switching
    const outerMats = [];
    const innerMats = [];
    const edgeMats = [];

    for (let x = -1; x <= 1; x++) {
      for (let y = -1; y <= 1; y++) {
        for (let z = -1; z <= 1; z++) {
          const cg = new THREE.Group();
          cg.position.set(x*gap, y*gap, z*gap);
          const faces = [
            {rot:[0,Math.PI/2,0],pos:[offset,0,0],outer:x===1},
            {rot:[0,-Math.PI/2,0],pos:[-offset,0,0],outer:x===-1},
            {rot:[-Math.PI/2,0,0],pos:[0,offset,0],outer:y===1},
            {rot:[Math.PI/2,0,0],pos:[0,-offset,0],outer:y===-1},
            {rot:[0,0,0],pos:[0,0,offset],outer:z===1},
            {rot:[0,Math.PI,0],pos:[0,0,-offset],outer:z===-1},
          ];
          faces.forEach(f => {
            const geo = f.outer ? planeGeo : flatGeo;
            const mat = (f.outer ? whiteMat : purpleMat).clone();
            if (f.outer) outerMats.push(mat); else innerMats.push(mat);
            const p = new THREE.Mesh(geo, mat);
            p.rotation.set(f.rot[0],f.rot[1],f.rot[2]);
            p.position.set(f.pos[0],f.pos[1],f.pos[2]);
            cg.add(p);
            if (f.outer) {
              const em = edgeMat.clone();
              edgeMats.push(em);
              const e = new THREE.LineSegments(new THREE.EdgesGeometry(geo), em);
              e.rotation.set(f.rot[0],f.rot[1],f.rot[2]);
              e.position.set(f.pos[0],f.pos[1],f.pos[2]);
              cg.add(e);
            }
          });
          cubeObj.add(cg);
        }
      }
    }

    // Watch for theme changes
    const themeObserver = new MutationObserver(() => {
      const light = document.documentElement.getAttribute('data-theme') === 'light';
      outerMats.forEach(m => m.color.set(light ? '#ffffff' : '#2F2F2F'));
      innerMats.forEach(m => m.color.set(light ? '#F3EAF9' : '#675B56'));
      edgeMats.forEach(m => m.color.set(light ? 0x000000 : 0xE4E4E4));
      floorMat.opacity = light ? 0.06 : 0.35;
    });
    themeObserver.observe(document.documentElement, { attributes: true, attributeFilter: ['data-theme'] });

    // Invisible shadow caster — a solid box matching cube size
    const shadowBoxGeo = new THREE.BoxGeometry(S * 0.98, S * 0.98, S * 0.98);
    const shadowBoxMat = new THREE.MeshStandardMaterial({ colorWrite: false });
    const shadowBox = new THREE.Mesh(shadowBoxGeo, shadowBoxMat);
    shadowBox.castShadow = true;
    cubeObj.add(shadowBox);

    // The cube sits inside a pivot. Cube center is at (0, H, 0) so bottom is at y=0
    const pivot = new THREE.Group();
    cubeObj.position.set(0, H, 0);
    pivot.add(cubeObj);
    scene.add(pivot);

    // State
    let rolling = false;
    let rollCount = 0;
    const startX = isMobile 
      ? -viewSize * aspect + S / 2  // extreme left edge
      : -viewSize * aspect * 0.4;   // 30% from left on desktop
    let baseX = startX;
    let cumAngle = 0;

    pivot.position.x = baseX;
    cubeObj.rotation.z = cumAngle;

    camera.position.set(0, 4, 10);
    camera.lookAt(0, H, 0);

    const roll = (dir) => {
      // dir: 1=right, -1=left
      return new Promise(resolve => {
        // Before rolling, set pivot position and reset
        pivot.position.set(baseX, 0, 0);
        pivot.rotation.z = 0;
        cubeObj.position.set(0, H, 0);
        cubeObj.rotation.z = cumAngle;

        // Move pivot to the leading edge
        // Rolling right: pivot at bottom-right edge = (H, 0, 0)
        // Rolling left: pivot at bottom-left edge = (-H, 0, 0)
        const edgeX = H * dir;

        // Shift pivot to that edge
        pivot.position.x = baseX + edgeX;
        // Offset cubeObj so it stays in place
        cubeObj.position.x = -edgeX;
        cubeObj.position.y = H;

        const targetAngle = (-Math.PI / 2) * dir;
        const duration = 600;
        const start = performance.now();

        const tween = (now) => {
          const t = Math.min((now - start) / duration, 1);
          const ease = t < 0.5 ? 2*t*t : 1 - Math.pow(-2*t+2, 2)/2;

          pivot.rotation.z = targetAngle * ease;

          if (t >= 1) {
            // Absorb rotation
            cumAngle += targetAngle;
            baseX += S * dir;
            rollCount += dir;
            if (onRoll) onRoll(rollCount);

            // Reset pivot
            pivot.position.set(baseX, 0, 0);
            pivot.rotation.z = 0;
            cubeObj.position.set(0, H, 0);
            cubeObj.rotation.z = cumAngle;

            // Bounce on landing (non-blocking)
            playThud();
            const bounceDur = 200;
            const bounceStart = performance.now();
            const bounceAmt = 0.04;
            const bounceFn = (now2) => {
              const bt = Math.min((now2 - bounceStart) / bounceDur, 1);
              const bounce = Math.sin(bt * Math.PI) * bounceAmt * (1 - bt);
              cubeObj.rotation.z = cumAngle + bounce * dir;
              if (bt >= 1) { cubeObj.rotation.z = cumAngle; return; }
              requestAnimationFrame(bounceFn);
            };
            requestAnimationFrame(bounceFn);

            resolve();
            return;
          }
          requestAnimationFrame(tween);
        };
        requestAnimationFrame(tween);
      });
    };

    let scrollAccum = 0;
    const scrollPerRoll = 120;
    let idleTimer = null;

    const snapTo = (target) => {
      // target: 0 = fall back, 1 = fall forward
      rolling = true;
      const startAccum = scrollAccum;
      const dir = startAccum > 0 ? 1 : -1;
      const targetAccum = target === 1 ? scrollPerRoll * dir : 0;
      const duration = 250;
      const start = performance.now();

      const tween = (now) => {
        const t = Math.min((now - start) / duration, 1);
        // Accelerating ease (gravity feel)
        const ease = t * t * t;
        scrollAccum = startAccum + (targetAccum - startAccum) * ease;

        if (Math.abs(scrollAccum) < 1 && target === 0) {
          // Snapped back
          scrollAccum = 0;
          pivot.position.set(baseX, 0, 0);
          pivot.rotation.z = 0;
          cubeObj.position.set(0, H, 0);
          cubeObj.rotation.z = cumAngle;
          rolling = false;
          return;
        }

        // Update rotation
        const progress = scrollAccum / scrollPerRoll;
        const angle = (-Math.PI / 2) * progress;
        const edgeX = H * dir;
        pivot.position.x = baseX + edgeX;
        pivot.rotation.z = 0;
        cubeObj.position.x = -edgeX;
        cubeObj.position.y = H;
        cubeObj.rotation.z = cumAngle;
        pivot.rotation.z = angle;

        if (t >= 1 && target === 1) {
          // Completed forward
          playThud();
          cumAngle += (-Math.PI / 2) * dir;
          baseX += S * dir;
          rollCount += dir;
          if (onRoll) onRoll(rollCount);
          scrollAccum = 0;
          pivot.position.set(baseX, 0, 0);
          pivot.rotation.z = 0;
          cubeObj.position.set(0, H, 0);
          cubeObj.rotation.z = cumAngle;
          rolling = false;
          return;
        }

        requestAnimationFrame(tween);
      };
      requestAnimationFrame(tween);
    };

    const handleWheel = (e) => {
      if (e.ctrlKey || e.metaKey) return;
      if (!activeRef.current) return;

      if (rolling) { e.preventDefault(); return; }

      const dir = e.deltaY > 0 ? 1 : -1;
      const atEnd = maxRolls != null && rollCount >= maxRolls && dir === 1;
      const atStart = rollCount <= 0 && dir === -1;

      if (atEnd || atStart) {
        scrollAccum = 0;
        if (atEnd && onEnd) onEnd(1);
        if (atStart && onEnd) onEnd(-1);
        return;
      }

      e.preventDefault();

      // Reset idle timer
      if (idleTimer) clearTimeout(idleTimer);

      scrollAccum += e.deltaY * 0.8;
      const scrollDir = scrollAccum > 0 ? 1 : -1;

      if (Math.abs(scrollAccum) >= scrollPerRoll) {
        // Complete the roll instantly
        cumAngle += (-Math.PI / 2) * scrollDir;
        baseX += S * scrollDir;
        rollCount += scrollDir;
        if (onRoll) onRoll(rollCount);
        scrollAccum = 0;
        pivot.position.set(baseX, 0, 0);
        pivot.rotation.z = 0;
        cubeObj.position.set(0, H, 0);
        cubeObj.rotation.z = cumAngle;
      } else {
        // Partial rotation
        const progress = scrollAccum / scrollPerRoll;
        const angle = (-Math.PI / 2) * progress;
        const edgeX = H * scrollDir;
        pivot.position.x = baseX + edgeX;
        pivot.rotation.z = 0;
        cubeObj.position.x = -edgeX;
        cubeObj.position.y = H;
        cubeObj.rotation.z = cumAngle;
        pivot.rotation.z = angle;


        // Start idle timer — if scroll stops, snap
        const absProgress = Math.abs(scrollAccum) / scrollPerRoll;
        idleTimer = setTimeout(() => {
          if (rolling) return;
          const p = Math.abs(scrollAccum) / scrollPerRoll;
          if (p > 0.5) {
            snapTo(1);
          } else if (p > 0.01) {
            snapTo(0);
          }
        }, absProgress > 0.5 ? 0 : 50);
      }
    };
    window.addEventListener('wheel', handleWheel, { passive: false });

    // Touch/swipe support for mobile
    let touchStartY = null;
    let touchAccum = 0;

    const handleTouchStart = (e) => {
      if (!activeRef.current) return;
      touchStartY = e.touches[0].clientY;
      touchAccum = 0;
    };

    const handleTouchMove = (e) => {
      if (!activeRef.current || touchStartY === null) return;
      if (rolling) { e.preventDefault(); return; }

      const currentY = e.touches[0].clientY;
      const deltaY = touchStartY - currentY; // positive = swipe up = scroll down
      touchStartY = currentY;

      const dir = deltaY > 0 ? 1 : -1;
      const atEnd = maxRolls != null && rollCount >= maxRolls && dir === 1;
      const atStart = rollCount <= 0 && dir === -1;

      if (atEnd || atStart) {
        scrollAccum = 0;
        if (atEnd && onEnd) onEnd(1);
        if (atStart && onEnd) onEnd(-1);
        return;
      }

      e.preventDefault();

      if (idleTimer) clearTimeout(idleTimer);

      scrollAccum += deltaY * 1.5;
      const scrollDir = scrollAccum > 0 ? 1 : -1;

      if (Math.abs(scrollAccum) >= scrollPerRoll) {
        cumAngle += (-Math.PI / 2) * scrollDir;
        baseX += S * scrollDir;
        rollCount += scrollDir;
        if (onRoll) onRoll(rollCount);
        scrollAccum = 0;
        pivot.position.set(baseX, 0, 0);
        pivot.rotation.z = 0;
        cubeObj.position.set(0, H, 0);
        cubeObj.rotation.z = cumAngle;
        playThud();
      } else {
        const progress = scrollAccum / scrollPerRoll;
        const angle = (-Math.PI / 2) * progress;
        const edgeX = H * scrollDir;
        pivot.position.x = baseX + edgeX;
        pivot.rotation.z = 0;
        cubeObj.position.x = -edgeX;
        cubeObj.position.y = H;
        cubeObj.rotation.z = cumAngle;
        pivot.rotation.z = angle;
      }
    };

    const handleTouchEnd = () => {
      touchStartY = null;
      if (rolling || Math.abs(scrollAccum) < 1) return;
      const p = Math.abs(scrollAccum) / scrollPerRoll;
      if (p > 0.3) {
        snapTo(1);
      } else {
        snapTo(0);
      }
    };

    window.addEventListener('touchstart', handleTouchStart, { passive: true });
    window.addEventListener('touchmove', handleTouchMove, { passive: false });
    window.addEventListener('touchend', handleTouchEnd, { passive: true });

    let raf;
    const animate = () => {
      // Light follows cube so shadow stays correct
      dir.position.set(baseX + 8, 8, 3);
      dir.target.position.set(baseX, 0, 0);
      dir.target.updateMatrixWorld();
      floor.position.x = baseX;
      renderer.render(scene, camera);
      raf = requestAnimationFrame(animate);
    };
    raf = requestAnimationFrame(animate);

    const handleResize = () => {
      const nw = container.clientWidth || 400;
      const nh = container.clientHeight || 400;
      const a = nw / nh;
      const vs = window.innerWidth <= 768 ? 4 : 5;
      camera.left = -vs * a;
      camera.right = vs * a;
      camera.top = vs;
      camera.bottom = -vs;
      camera.updateProjectionMatrix();
      renderer.setSize(nw, nh);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(raf);
      themeObserver.disconnect();
      window.removeEventListener('wheel', handleWheel);
      window.removeEventListener('touchstart', handleTouchStart);
      window.removeEventListener('touchmove', handleTouchMove);
      window.removeEventListener('touchend', handleTouchEnd);
      window.removeEventListener('resize', handleResize);
      if (container.contains(renderer.domElement)) container.removeChild(renderer.domElement);
      renderer.dispose();
    };
  }, []);

  return <div ref={mountRef} className="rubik-container" />;
}
