import React, { useRef, useEffect } from 'react';

const PAD = 400;
const MOBILE_PAD = 150;

function getPad() {
  return window.innerWidth <= 768 ? MOBILE_PAD : PAD;
}

export default function PixelPhoto({ src, size = 240 }) {
  const canvasRef = useRef(null);
  const imgRef = useRef(null);
  const mouseRef = useRef({ x: -999, y: -999 });
  const draggingRef = useRef(null);
  const springBackRef = useRef(false);
  const padRef = useRef(getPad());
  const half = size / 2;
  const origDots = [
    { id: 'top', x: 0, y: -half, tx: 1, ty: 0 },
    { id: 'right', x: half, y: 0, tx: 0, ty: 1 },
    { id: 'bottom', x: 0, y: half, tx: 1, ty: 0 },
    { id: 'left', x: -half, y: 0, tx: 0, ty: 1 },
  ];
  const dotsRef = useRef(origDots.map((d, i) => {
    // Start bottom dot stretched
    if (d.id === 'top') return { ...d, y: -half - 20 };
    return { ...d };
  }));
  const introAnimDone = useRef(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    const pad = padRef.current;
    const totalSize = size + pad * 2;
    canvas.width = totalSize * dpr;
    canvas.height = totalSize * dpr;
    ctx.scale(dpr, dpr);

    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => {
      imgRef.current = img;
      startLoop();
    };
    img.src = src;

    const cx = totalSize / 2;
    const cy = totalSize / 2;
    const proximity = 40;
    const dotR = 4;

    const drawFrame = () => {
      const ts = totalSize;
      ctx.clearRect(0, 0, ts, ts);
      const dots = dotsRef.current;

      const K = 0.5523;
      // Absolute positions
      const t = { x: cx + dots[0].x, y: cy + dots[0].y };
      const r = { x: cx + dots[1].x, y: cy + dots[1].y };
      const b = { x: cx + dots[2].x, y: cy + dots[2].y };
      const l = { x: cx + dots[3].x, y: cy + dots[3].y };

      // Draw image clipped to bezier shape
      ctx.save();
      ctx.beginPath();
      ctx.moveTo(t.x, t.y);
      ctx.bezierCurveTo(t.x + (r.x - cx) * K, t.y, r.x, r.y - (cy - t.y) * K, r.x, r.y);
      ctx.bezierCurveTo(r.x, r.y + (b.y - cy) * K, b.x + (r.x - cx) * K, b.y, b.x, b.y);
      ctx.bezierCurveTo(b.x - (cx - l.x) * K, b.y, l.x, l.y + (b.y - cy) * K, l.x, l.y);
      ctx.bezierCurveTo(l.x, l.y - (cy - t.y) * K, t.x - (cx - l.x) * K, t.y, t.x, t.y);
      ctx.closePath();
      ctx.clip();

      // Vibrant blue background behind image
      ctx.fillStyle = '#314DF7';
      ctx.fillRect(0, 0, ts, ts);

      // Repeating CONFIDENTIAL watermark at 45 degrees - marquee
      ctx.save();
      ctx.translate(ts / 2, ts / 2);
      ctx.rotate(-Math.PI / 4);
      ctx.font = '700 22px Inter, sans-serif';
      ctx.fillStyle = 'rgba(255,255,255,0.25)';
      ctx.textAlign = 'left';
      const text = 'CONFIDENTIAL  ★  ';
      const repeatText = text.repeat(15);
      marqueeOffset = (marqueeOffset + 0.5) % 300;
      let rowIdx = 0;
      for (let y = -ts * 1.5; y < ts * 1.5; y += 36) {
        const dir = rowIdx % 2 === 0 ? -1 : 1;
        ctx.fillText(repeatText, -ts * 1.5 + marqueeOffset * dir, y);
        rowIdx++;
      }
      ctx.restore();

      const scale = 1.3;
      const drawW = size * scale;
      const drawH = (img.height / img.width) * drawW;
      const drawX = cx - drawW / 2;
      const isMobile = window.innerWidth <= 768;
      const faceOffset = isMobile ? 150 : 200;
      const drawY = cy - drawH / 2 - faceOffset + size / 2;
      ctx.drawImage(img, 0, 0, img.width, img.height, drawX, drawY, drawW, drawH);
      ctx.restore();

      // Shape outline
      ctx.strokeStyle = '#4A90D9';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(t.x, t.y);
      ctx.bezierCurveTo(t.x + (r.x - cx) * K, t.y, r.x, r.y - (cy - t.y) * K, r.x, r.y);
      ctx.bezierCurveTo(r.x, r.y + (b.y - cy) * K, b.x + (r.x - cx) * K, b.y, b.x, b.y);
      ctx.bezierCurveTo(b.x - (cx - l.x) * K, b.y, l.x, l.y + (b.y - cy) * K, l.x, l.y);
      ctx.bezierCurveTo(l.x, l.y - (cy - t.y) * K, t.x - (cx - l.x) * K, t.y, t.x, t.y);
      ctx.closePath();
      ctx.stroke();

      // Mouse position
      const rect = canvas.getBoundingClientRect();
      const mx = (mouseRef.current.x - rect.left) * (ts / rect.width);
      const my = (mouseRef.current.y - rect.top) * (ts / rect.height);

      const positions = [t, r, b, l];
      dots.forEach((dot, i) => {
        const pos = positions[i];
        const dx = mx - pos.x;
        const dy = my - pos.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        
        // Check proximity to dot, tangent line, or square endpoints
        const lx1 = pos.x - dot.tx * 80;
        const ly1 = pos.y - dot.ty * 80;
        const lx2 = pos.x + dot.tx * 80;
        const ly2 = pos.y + dot.ty * 80;
        
        // Distance to line segment
        const lineDx = lx2 - lx1;
        const lineDy = ly2 - ly1;
        const lineLen = Math.sqrt(lineDx * lineDx + lineDy * lineDy);
        const t2 = Math.max(0, Math.min(1, ((mx - lx1) * lineDx + (my - ly1) * lineDy) / (lineLen * lineLen)));
        const projX = lx1 + t2 * lineDx;
        const projY = ly1 + t2 * lineDy;
        const lineDist = Math.sqrt((mx - projX) ** 2 + (my - projY) ** 2);
        
        const nearDot = dist < proximity;
        const nearLine = lineDist < 25;
        const introShowTop = !introAnimDone.current && dot.id === 'top';
        const near = nearDot || nearLine || draggingRef.current === dot.id || introShowTop;

        if (near) {
          // 1. Tangent line (behind everything)
          ctx.beginPath();
          ctx.moveTo(lx1, ly1);
          ctx.lineTo(lx2, ly2);
          ctx.strokeStyle = '#999';
          ctx.lineWidth = 1;
          ctx.stroke();

          // 2. Square endpoints
          const sq = 3;
          [{ ex: lx1, ey: ly1 }, { ex: lx2, ey: ly2 }].forEach(({ ex, ey }) => {
            ctx.fillStyle = '#fff';
            ctx.fillRect(ex - sq, ey - sq, sq * 2, sq * 2);
            ctx.strokeStyle = '#4A90D9';
            ctx.lineWidth = 1.5;
            ctx.strokeRect(ex - sq, ey - sq, sq * 2, sq * 2);
          });

          // 3. Dot circle (on top)
          ctx.beginPath();
          ctx.arc(pos.x, pos.y, dotR, 0, Math.PI * 2);
          ctx.fillStyle = '#4A90D9';
          ctx.fill();
          ctx.strokeStyle = '#fff';
          ctx.lineWidth = 2;
          ctx.stroke();
        } else {
          ctx.beginPath();
          ctx.arc(pos.x, pos.y, dotR, 0, Math.PI * 2);
          ctx.fillStyle = '#fff';
          ctx.fill();
          ctx.strokeStyle = '#4A90D9';
          ctx.lineWidth = 2;
          ctx.stroke();
        }
      });
    };

    let raf;
    let marqueeOffset = 0;

    // Intro animation: spring back bottom dot after delay
    setTimeout(() => {
      if (introAnimDone.current) return;
      introAnimDone.current = true;
      springBackRef.current = true;
      const velocity = [];
      dotsRef.current.forEach(() => velocity.push({ vx: 0, vy: 0 }));
      const stiffness = 0.5;
      const damping = 0.7;
      const springIntro = () => {
        let allSettled = true;
        dotsRef.current.forEach((dot, i) => {
          const orig = origDots[i];
          const dx = orig.x - dot.x;
          const dy = orig.y - dot.y;
          velocity[i].vx = (velocity[i].vx + dx * stiffness) * damping;
          velocity[i].vy = (velocity[i].vy + dy * stiffness) * damping;
          dot.x += velocity[i].vx;
          dot.y += velocity[i].vy;
          if (Math.abs(dx) > 0.2 || Math.abs(dy) > 0.2 || Math.abs(velocity[i].vx) > 0.1 || Math.abs(velocity[i].vy) > 0.1) {
            allSettled = false;
          } else {
            dot.x = orig.x;
            dot.y = orig.y;
          }
        });
        if (!allSettled) {
          requestAnimationFrame(springIntro);
        } else {
          springBackRef.current = false;
        }
      };
      requestAnimationFrame(springIntro);
    }, 200);

    const startLoop = () => {
      const loop = () => {
        if (imgRef.current) drawFrame();
        raf = requestAnimationFrame(loop);
      };
      raf = requestAnimationFrame(loop);
    };

    const handleMouseMove = (e) => {
      mouseRef.current = { x: e.clientX, y: e.clientY };

      if (draggingRef.current) {
        const rect = canvas.getBoundingClientRect();
        const ts = totalSize;
        const mx = (e.clientX - rect.left) * (ts / rect.width);
        const my = (e.clientY - rect.top) * (ts / rect.height);

        const dot = dotsRef.current.find(d => d.id === draggingRef.current);
        if (dot) {
          dot.x = mx - cx;
          dot.y = my - cy;
        }
      }
    };

    const handleMouseDown = (e) => {
      const rect = canvas.getBoundingClientRect();
      const ts = totalSize;
      const mx = (e.clientX - rect.left) * (ts / rect.width);
      const my = (e.clientY - rect.top) * (ts / rect.height);

      const dots = dotsRef.current;
      const positions = [
        { x: cx + dots[0].x, y: cy + dots[0].y },
        { x: cx + dots[1].x, y: cy + dots[1].y },
        { x: cx + dots[2].x, y: cy + dots[2].y },
        { x: cx + dots[3].x, y: cy + dots[3].y },
      ];

      for (let i = 0; i < dots.length; i++) {
        const dx = mx - positions[i].x;
        const dy = my - positions[i].y;
        if (Math.sqrt(dx * dx + dy * dy) < proximity) {
          draggingRef.current = dots[i].id;
          e.preventDefault();
          break;
        }
      }
    };

    const handleMouseUp = () => {
      if (draggingRef.current) {
        draggingRef.current = null;
        springBackRef.current = true;
        
        // Snap back angrily with spring overshoot
        setTimeout(() => {
          let velocity = [];
          dotsRef.current.forEach(() => velocity.push({ vx: 0, vy: 0 }));
          const stiffness = 0.5;
          const damping = 0.7;

          const springBack = () => {
            let allSettled = true;
            dotsRef.current.forEach((dot, i) => {
              const orig = origDots[i];
              const dx = orig.x - dot.x;
              const dy = orig.y - dot.y;
              
              velocity[i].vx = (velocity[i].vx + dx * stiffness) * damping;
              velocity[i].vy = (velocity[i].vy + dy * stiffness) * damping;
              dot.x += velocity[i].vx;
              dot.y += velocity[i].vy;

              if (Math.abs(dx) > 0.2 || Math.abs(dy) > 0.2 || Math.abs(velocity[i].vx) > 0.1 || Math.abs(velocity[i].vy) > 0.1) {
                allSettled = false;
              } else {
                dot.x = orig.x;
                dot.y = orig.y;
              }
            });
            if (!allSettled) {
              requestAnimationFrame(springBack);
            } else {
              springBackRef.current = false;
            }
          };
          requestAnimationFrame(springBack);
        }, 30);
      }
    };

    window.addEventListener('mousemove', handleMouseMove);
    canvas.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);

    // Touch support for mobile
    const handleTouchStart = (e) => {
      const touch = e.touches[0];
      const rect = canvas.getBoundingClientRect();
      const ts = totalSize;
      const mx = (touch.clientX - rect.left) * (ts / rect.width);
      const my = (touch.clientY - rect.top) * (ts / rect.height);

      const dots = dotsRef.current;
      const positions = [
        { x: cx + dots[0].x, y: cy + dots[0].y },
        { x: cx + dots[1].x, y: cy + dots[1].y },
        { x: cx + dots[2].x, y: cy + dots[2].y },
        { x: cx + dots[3].x, y: cy + dots[3].y },
      ];

      for (let i = 0; i < dots.length; i++) {
        const dx = mx - positions[i].x;
        const dy = my - positions[i].y;
        if (Math.sqrt(dx * dx + dy * dy) < proximity * 2) {
          draggingRef.current = dots[i].id;
          e.preventDefault();
          break;
        }
      }
    };

    const handleTouchMove = (e) => {
      const touch = e.touches[0];
      mouseRef.current = { x: touch.clientX, y: touch.clientY };

      if (draggingRef.current) {
        e.preventDefault();
        const rect = canvas.getBoundingClientRect();
        const ts = totalSize;
        const mx = (touch.clientX - rect.left) * (ts / rect.width);
        const my = (touch.clientY - rect.top) * (ts / rect.height);

        const dot = dotsRef.current.find(d => d.id === draggingRef.current);
        if (dot) {
          dot.x = mx - cx;
          dot.y = my - cy;
        }
      }
    };

    const handleTouchEnd = () => {
      handleMouseUp();
    };

    canvas.addEventListener('touchstart', handleTouchStart, { passive: false });
    canvas.addEventListener('touchmove', handleTouchMove, { passive: false });
    canvas.addEventListener('touchend', handleTouchEnd);

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('mousemove', handleMouseMove);
      canvas.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      canvas.removeEventListener('touchstart', handleTouchStart);
      canvas.removeEventListener('touchmove', handleTouchMove);
      canvas.removeEventListener('touchend', handleTouchEnd);
    };
  }, [src, size]);

  const pad = getPad();
  return (
    <canvas
      ref={canvasRef}
      style={{
        width: size + pad * 2,
        height: size + pad * 2,
        cursor: 'default',
        margin: -pad + 'px',
      }}
    />
  );
}
