import React, { useState, useRef, useCallback, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import RubikCube from './RubikCube';
import PixelPhoto from './PixelPhoto';
import Contact from './Contact';
import './About.css';

const SLIDES = [
  { name: 'NIFT Bengaluru', subtitle: 'B.Des Fashion Communication · 8.2 CGPA · 2015-2019', role: 'Education', desc: 'Built a strong foundation in design thinking, visual communication, and human-computer interaction.', year: 2015 },
  { name: 'Designit, Wipro', subtitle: 'Graduation Project · Jan-May 2019', role: 'Experience Designer', desc: 'Redesigned Wipro deal pursuit experiences to support existing and future business models through a human-centric approach.', year: 2019 },
  { name: 'Star TV Network', subtitle: 'Walt Disney Company · Jul 2019-Dec 2020', role: 'Executive Designer', desc: 'Delivered end-to-end UX for SaaS B2B products and dashboards leveraging data for pricing, Ad inventory, and monetisation.', year: 2019 },
  { name: 'MakeMyTrip', subtitle: 'Dec 2020-Oct 2022', role: 'Product Designer', desc: 'Crafted end-to-end experiences for Trains & Cabs funnels, bringing consistency across platforms.', year: 2020 },
  { name: 'Razorpay', subtitle: 'Oct 2022-Nov 2023', role: 'Sr. Product Designer', desc: 'Reimagined onboarding for Lending and Corporate Card platform within Razorpay Capital.', year: 2022 },
  { name: 'Intuit', subtitle: 'Nov 2023-Oct 2024', role: 'Sr. Product Designer', desc: 'Improving the lifecycle of Intuit\'s Experts with AI and data-driven research — from onboarding and training to scheduling and off-boarding.', year: 2023 },
  { name: 'Microsoft', subtitle: 'Nov 2024-Present', role: 'Sr. Product Designer', desc: 'Building AI agents and governance tools impacting millions of enterprise users.', year: 2024 },
];

const variants = {
  enter: (dir) => ({ y: dir === 1 ? 30 : -30, opacity: 0 }),
  center: { y: 0, opacity: 1 },
  exit: (dir) => ({ y: dir === 1 ? -30 : 30, opacity: 0 }),
};

export default function About() {
  const [rollIndex, setRollIndex] = useState(0);
  const [dir, setDir] = useState(1);
  const prevIndex = useRef(0);

  const rollToSlide = [0, 1, 2, 3, 4, 5, 6];
  const maxRolls = rollToSlide.length - 1;

  const handleRoll = useCallback((newIndex) => {
    const clampedRoll = Math.max(0, Math.min(maxRolls, newIndex));
    const slideIdx = rollToSlide[clampedRoll];
    const d = slideIdx > prevIndex.current ? 1 : slideIdx < prevIndex.current ? -1 : 1;
    if (slideIdx !== prevIndex.current) {
      prevIndex.current = slideIdx;
      setDir(d);
    }
    setRollIndex(slideIdx);
    // Reset end state when cube is rolling
    if (cubeAtEndRef.current && clampedRoll < maxRolls) {
      cubeAtEndRef.current = false;
    }
  }, []);

  const handleEnd = useCallback((direction) => {
    setScrollLocked(false);
    if (direction > 0) {
      cubeAtEndRef.current = true;
    }
    cooldownRef.current = true;
    setTimeout(() => { cooldownRef.current = false; }, 300);
  }, []);

  const slide = SLIDES[rollIndex];
  const timelineRef = useRef(null);
  const [scrollLocked, setScrollLocked] = useState(false);
  const cooldownRef = useRef(false);

  const cubeAtEndRef = useRef(false);

  // Lock body scroll when timeline is in view
  useEffect(() => {
    let lastScrollY = window.scrollY;
    const checkPosition = () => {
      if (!timelineRef.current || cooldownRef.current) return;
      const rect = timelineRef.current.getBoundingClientRect();
      const scrollingDown = window.scrollY > lastScrollY;
      lastScrollY = window.scrollY;
      
      const shouldLock = rect.top <= 5 && rect.bottom > window.innerHeight * 0.5;
      
      // Reset cubeAtEnd when scrolling up and timeline is at top
      if (shouldLock && !scrollingDown && cubeAtEndRef.current) {
        cubeAtEndRef.current = false;
        cooldownRef.current = false;
      }
      
      if (!cubeAtEndRef.current && !cooldownRef.current) {
        setScrollLocked(shouldLock);
      }
    };
    window.addEventListener('scroll', checkPosition, { passive: true });
    checkPosition();

    // Prevent native touch scrolling when cube is locked (mobile)
    const preventTouchScroll = (e) => {
      if (document.body.style.overflow === 'hidden') {
        e.preventDefault();
      }
    };
    document.addEventListener('touchmove', preventTouchScroll, { passive: false });

    return () => {
      window.removeEventListener('scroll', checkPosition);
      document.removeEventListener('touchmove', preventTouchScroll);
    };
  }, []);

  useEffect(() => {
    if (scrollLocked) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    // Always hide scrollbar to prevent layout shift
    document.documentElement.style.scrollbarWidth = 'none';
    document.documentElement.style.setProperty('-ms-overflow-style', 'none');
    return () => {
      document.body.style.overflow = '';
      document.documentElement.style.scrollbarWidth = '';
    };
  }, [scrollLocked]);

  const [photoSize, setPhotoSize] = useState(window.innerWidth <= 768 ? 160 : 240);

  useEffect(() => {
    const handleResize = () => {
      setPhotoSize(window.innerWidth <= 768 ? 160 : 240);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return (
    <div className="about-wrapper">
      {/* 1. About Me intro */}
      <section className="about-intro">
        <div className="about-intro-content">
          <div className="about-intro-photo">
            <PixelPhoto src={process.env.PUBLIC_URL + '/Personal/Self.jpg'} size={photoSize} />
          </div>
          <motion.h1
            className="about-intro-title"
            initial={{ y: 40, opacity: 0 }}
            whileInView={{ y: 0, opacity: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
          >
            Entropy bothers me
          </motion.h1>
          <motion.p
            className="about-intro-text"
            initial={{ y: 30, opacity: 0 }}
            whileInView={{ y: 0, opacity: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8, delay: 0.2 }}
          >
            The universe tends toward chaos. I craft order - one product at a time.
          </motion.p>
          <motion.p
            className="about-intro-bio"
            initial={{ y: 20, opacity: 0 }}
            whileInView={{ y: 0, opacity: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8, delay: 0.4 }}
          >
            I'm a Product Designer based in Bangalore, India. <span style={{ fontSize: '1.3em' }}>🌴</span>
            {' '}I've <strong>shipped products for 100M+ users across AI, fintech, travel</strong>, and media — and occasionally take on select <a href={process.env.PUBLIC_URL + '/?tab=other'} style={{ color: 'inherit', textDecoration: 'underline' }}>client work</a> on the side.
            <br /><br />
            At age 13, I was animating characters in PowerPoint before I knew design was a real career. The obsession never left — just the tools changed.
            {' '}When I'm not designing, I'm on chess.com <span style={{ fontSize: '1.3em' }}>♟️</span>, Netflix, or on my bike going nowhere in particular. Weekends usually involve badminton, Vietnamese coffee <span style={{ fontSize: '1.3em' }}>☕</span>, and good company.
            <br /><br />
            Currently figuring out adulting — between Himalayan treks, transatlantic flights, attending weddings, and family calls.
          </motion.p>
        </div>
      </section>

      {/* 2. Career timeline + Rubik cube */}
      <div className="about-timeline-container" ref={timelineRef}>
        <section className="about-timeline">
        <div className="about-fixed-layer">
          <div className="cube-stage">
            <RubikCube onRoll={handleRoll} maxRolls={maxRolls} onEnd={handleEnd} active={scrollLocked} />
          </div>
          <div className="floor-line">
            {SLIDES.map((s, i) => {
              const gapYears = i > 0 ? s.year - SLIDES[i - 1].year : 0;
              const duplicateYear = i > 0 && s.year === SLIDES[i - 1].year;
              return (
                <React.Fragment key={i}>
                  {i > 0 && <div className="floor-gap" style={{ flex: Math.max(gapYears, 0.5) }} />}
                  <div className={`floor-mark ${i === rollIndex ? 'active' : ''} ${i < rollIndex ? 'passed' : ''}`}>
                    {!duplicateYear && <span className="floor-year">{s.year}</span>}
                  </div>
                </React.Fragment>
              );
            })}
          </div>
          <div className="company-display">
            <AnimatePresence mode="popLayout" initial={false} custom={dir}>
              <motion.div
                key={rollIndex}
                className="company-card"
                custom={dir}
                variants={variants}
                initial="enter"
                animate="center"
                exit="exit"
                transition={{ duration: 0.1 }}
              >
                <span className="company-role">{slide.role}</span>
                <h2 className="company-name-display">{slide.name}</h2>
                <span className="company-subtitle">{slide.subtitle}</span>
                {slide.desc && <p className="company-desc">{slide.desc}</p>}
              </motion.div>
            </AnimatePresence>
          </div>
        </div>
      </section>
      </div>

      {/* 3. Moments marquee */}
      <section className="about-gallery-section">
        <div className="about-marquee">
          <div className="about-marquee-track">
            {['IMG_3291.jpg','EB6F47B0-276F-4482-B8E9-1F5CD58BB32E.jpg','IMG_8170.jpg','IMG_0293.jpg','IMG_7386.jpg','IMG_0581.jpg','IMG_9992.jpg','IMG_3136.jpg','22301674-33A1-43F8-A9F1-78BDD6B80BC2-EDIT.jpg','IMG_5414.jpg','IMG_1719.jpg','IMG_0151.jpg','IMG_8974.jpg','IMG_1296.jpg','IMG_7462.jpg','IMG_0443 (1).jpg','IMG_9879.jpg','IMG_8525.jpg','IMG_3228.jpg','IMG_3291.jpg','EB6F47B0-276F-4482-B8E9-1F5CD58BB32E.jpg','IMG_8170.jpg','IMG_0293.jpg','IMG_7386.jpg','IMG_0581.jpg','IMG_9992.jpg','IMG_3136.jpg','22301674-33A1-43F8-A9F1-78BDD6B80BC2-EDIT.jpg','IMG_5414.jpg','IMG_1719.jpg','IMG_0151.jpg','IMG_8974.jpg','IMG_1296.jpg','IMG_7462.jpg','IMG_0443 (1).jpg','IMG_9879.jpg','IMG_8525.jpg','IMG_3228.jpg'].map((img, idx) => (
              <div key={idx} className="about-marquee-item">
                <img src={process.env.PUBLIC_URL + '/gallery-2/' + img} alt="" loading="lazy" />
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* 4. Footer */}
      <Contact />
    </div>
  );
}
